/**
 * ZxOTP BOT — Scripts library  (400+ built-in scripts)
 *
 * A "script" = the TTS message played when the target answers.
 * Users can browse by category, preview, select, and create custom scripts.
 */

// ── Types ─────────────────────────────────────────────────────────────────────

export type ScriptCategory =
  | 'bank_us'   | 'bank_uk'   | 'bank_ca'  | 'bank_au'  | 'bank_eu'
  | 'bank_asia' | 'bank_me'   | 'bank_af'  | 'bank_la'
  | 'payment'   | 'crypto'    | 'card'     | 'telecom'  | 'insurance'
  | 'retail'    | 'tech'      | 'govt'     | 'custom';

export const CAT_LABEL: Record<ScriptCategory, string> = {
  bank_us:   '🏦 US Banks',
  bank_uk:   '🏦 UK Banks',
  bank_ca:   '🏦 Canadian Banks',
  bank_au:   '🏦 Australian Banks',
  bank_eu:   '🏦 European Banks',
  bank_asia: '🏦 Asian Banks',
  bank_me:   '🏦 Middle East Banks',
  bank_af:   '🏦 African Banks',
  bank_la:   '🏦 Latin American Banks',
  payment:   '💳 Payment Platforms',
  crypto:    '₿  Crypto Exchanges',
  card:      '💳 Card Networks',
  telecom:   '📱 Telecom / ISP',
  insurance: '🛡 Insurance',
  retail:    '🛒 Retail & E-Commerce',
  tech:      '💻 Tech & Social',
  govt:      '🏛 Government',
  custom:    '✏️  My Custom Scripts',
};

export interface BuiltinScript {
  id:       string;
  name:     string;
  category: ScriptCategory;
  company:  string;
  country:  string;
  voice:    string;     // Amazon Polly voice ID
  message:  string;     // TTS text for /voice endpoint
  gather:   string;     // hold message after speech detected
}

export interface CustomScript {
  id:        string;
  name:      string;
  message:   string;
  gather:    string;
  voice:     string;
  createdAt: number;
}

// ── Shorthand helpers ──────────────────────────────────────────────────────────
const HOLD  = 'Thank you. Please hold while your response is being verified.';

// 5 voices — named by tone, not country
const SMOOTH = 'Polly.Joanna';   // Warm & Flowing   — female US
const DEEP   = 'Polly.Matthew';  // Low & Authoritative — male US
const CRISP  = 'Polly.Amy';      // Sharp & Professional — female UK
const MELLOW = 'Polly.Russell';  // Relaxed & Casual — male AU
const SHARP  = 'Polly.Aria';     // Clear & Distinct  — female NZ

// Legacy aliases so no script line needs changing (all map to one of the 5)
const JO  = SMOOTH;  const SAL = SMOOTH;  const KEN = SMOOTH;
const ADI = SMOOTH;  const RAV = SMOOTH;
const MT  = DEEP;    const JOE = DEEP;    const JUS = DEEP;
const AMY = CRISP;   const EMM = CRISP;   const KIM = CRISP;
const CEL = CRISP;   const VIC = CRISP;   const CON = CRISP;
const BRN = DEEP;
const NIC = MELLOW;  const RUS = MELLOW;
const ARR = SHARP;

// Additional varied hold messages so every script sounds different
const HOLD_SECURE = 'Thank you for your cooperation. Your response is being reviewed by our security team. Please remain on the line.';
const HOLD_BRIEF  = 'Understood. Please hold briefly while we process your verification.';
const HOLD_CHECK  = 'Thank you. Our fraud prevention team is reviewing your response. This will only take a moment.';

