// ══════════════════════════════════════════════════════════════════════════════
// Custom user scripts (in-memory, per user)
// ══════════════════════════════════════════════════════════════════════════════

const userScripts = new Map<number, CustomScript[]>();

export function getUserScripts(chatId: number): CustomScript[] {
  return userScripts.get(chatId) ?? [];
}

export function addUserScript(chatId: number, name: string, message: string, voice: string): CustomScript {
  const list = getUserScripts(chatId);
  const script: CustomScript = {
    id:        `custom_${chatId}_${Date.now()}`,
    name,
    message,
    gather:    HOLD,
    voice,
    createdAt: Date.now(),
  };
  userScripts.set(chatId, [...list, script]);
  return script;
}

export function editUserScript(chatId: number, scriptId: string, updates: Partial<Pick<CustomScript, 'name' | 'message' | 'voice'>>): boolean {
  const list = getUserScripts(chatId);
  const idx  = list.findIndex(s => s.id === scriptId);
  if (idx < 0) return false;
  list[idx] = { ...list[idx]!, ...updates };
  userScripts.set(chatId, list);
  return true;
}

export function deleteUserScript(chatId: number, scriptId: string): boolean {
  const list = getUserScripts(chatId);
  const next = list.filter(s => s.id !== scriptId);
  if (next.length === list.length) return false;
  userScripts.set(chatId, next);
  return true;
}

// ── Per-user active script ────────────────────────────────────────────────────

const activeScript = new Map<number, string>();

export function getActiveScript(chatId: number): string | undefined {
  return activeScript.get(chatId);
}

export function setActiveScript(chatId: number, scriptId: string): void {
  activeScript.set(chatId, scriptId);
}

export function clearActiveScript(chatId: number): void {
  activeScript.delete(chatId);
}

// ── Lookup helpers ────────────────────────────────────────────────────────────

export function getScript(id: string): BuiltinScript | undefined {
  return BUILTIN_SCRIPTS.find(s => s.id === id);
}

export function getScriptsByCategory(cat: ScriptCategory): BuiltinScript[] {
  return BUILTIN_SCRIPTS.filter(s => s.category === cat);
}

export function allCategories(): ScriptCategory[] {
  const seen = new Set<ScriptCategory>();
  const out:  ScriptCategory[] = [];
  for (const s of BUILTIN_SCRIPTS) {
    if (!seen.has(s.category)) { seen.add(s.category); out.push(s.category); }
  }
  out.push('custom');
  return out;
}

/**
 * Resolve a script id to {message, voice, gather}.
 * Works for both built-in and custom scripts.
 */
export function resolveScript(
  chatId: number,
  scriptId: string,
): { message: string; voice: string; gather: string } | undefined {
  const builtin = getScript(scriptId);
  if (builtin) return { message: builtin.message, voice: builtin.voice, gather: builtin.gather };
  const custom = getUserScripts(chatId).find(s => s.id === scriptId);
  if (custom)  return { message: custom.message,  voice: custom.voice,  gather: custom.gather };
  return undefined;
}

export function getScriptName(chatId: number, scriptId: string): string {
  return getScript(scriptId)?.name
    ?? getUserScripts(chatId).find(s => s.id === scriptId)?.name
    ?? scriptId;
}
